// CONFIGURATION — API keys injected via automation
const CONFIG = {
  anthropicApiKey: 'YOUR_ANTHROPIC_API_KEY',
  appUrl: 'https://autoapply.works',
  webhookSecret: 'e398a1c2b63259f396e61b08736f5d10'
};

const input = $input.first().json;
return [{ json: { ...input, _config: CONFIG } }];

// Validate and extract incoming webhook payload
const body = $input.first().json.body;
const config = $input.first().json._config;

if (!body || !body.jobDescription || !body.masterCvText || !body.userId || !body.jobId) {
  throw new Error('Missing required fields: jobDescription, masterCvText, userId, jobId');
}

return [{
  json: {
    userId: body.userId,
    jobId: body.jobId,
    jobTitle: body.jobTitle || '',
    company: body.company || '',
    jobDescription: body.jobDescription,
    masterCvText: body.masterCvText,
    anthropicApiKey: config.anthropicApiKey,
    appUrl: config.appUrl,
    webhookSecret: config.webhookSecret,
    additionalContext: body.additionalContext || ''
  }
}];

// Parse Anthropic scoring response, carry forward original data
const item = $input.first();
const prev = $('Validate Input').first().json;

try {
  const text = item.json.content?.[0]?.text || '';
  let jsonStr = text;
  const m = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) jsonStr = m[1];
  const p = JSON.parse(jsonStr.trim());

  return [{ json: {
    ...prev,
    compatibilityScore: p.compatibility_score || 0,
    atsKeywords: p.ats_keywords || [],
    matchingStrengths: p.matching_strengths || [],
    gaps: p.gaps || [],
    recommendation: p.recommendation || 'skip',
    scoringError: false
  }}];
} catch (e) {
  return [{ json: {
    ...prev,
    compatibilityScore: 50,
    atsKeywords: [],
    matchingStrengths: [],
    gaps: ['Unable to fully analyze - manual review recommended'],
    recommendation: 'stretch',
    scoringError: true,
    scoringErrorMsg: e.message
  }}];
}

